export const ALL_AIRPORTS: Airport[] = AIRPORT_DATABASE.flatMap(
  country => country.cities.flatMap(city => city.airports)
);

export function findAirportByIata(code: string): Airport | undefined {
  return ALL_AIRPORTS.find(a => a.iata === code.toUpperCase());
}

export function searchAirports(query: string): Airport[] {
  if (!query || query.length < 2) return [];
  const q = query.toLowerCase();
  return ALL_AIRPORTS.filter(a =>
    a.iata.toLowerCase().includes(q) ||
    a.name.toLowerCase().includes(q) ||
    a.city.toLowerCase().includes(q) ||
    a.country.toLowerCase().includes(q)
  ).slice(0, 15);
}
